pub fn parse <'t, T >
(input : &'t str, file_name : T, user_actions : & mut Grammar <'t>,) -> Result
< ParseTree, ParolError > where T : AsRef < Path >
{
    use parol_runtime ::
    {
        parser ::
        { parse_tree_type :: SynTree, parser_types :: SynTreeFlavor }, syntree
        :: Builder,
    }; let mut builder = Builder ::< SynTree, SynTreeFlavor >:: new_with();
    parse_into(input, & mut builder, file_name, user_actions) ?;
    Ok(builder.build() ?)
}#[allow(dead_code)] pub fn parse_into < 't, T : TreeConstruct < 't >>
(input : & 't str, tree_builder : & mut T, file_name : impl AsRef < Path >,
user_actions : & mut Grammar <'t>,) -> Result < (), ParolError > where ParolError :
From < T :: Error >
{
    use grammar_scanner ::GrammarScanner; let mut llk_parser = LLKParser ::
    new(64, LOOKAHEAD_AUTOMATA, PRODUCTIONS, TERMINAL_NAMES,
    NON_TERMINALS,);   let scanner = GrammarScanner :: new(); 
// Initialize wrapper
let mut user_actions = GrammarAuto :: new(user_actions);
    llk_parser.parse_into(tree_builder, TokenStream ::
    new(input, file_name, scanner.scanner_impl.clone(), &GrammarScanner ::
    match_function, MAX_K,).unwrap(), & mut user_actions)
}